prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org rdfs:label ?orgLabel . }
  FILTER(CONTAINS(STR(?model), "4ccc3fd711004f519782ac92e58f6ddd"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?normId)), "4ccc3fd7"))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(LCASE(STR(?modelName)), LCASE("4 augen")) || CONTAINS(LCASE(STR(?modelName)), LCASE("4-augen")))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?edgeType ?edge ?sourceName ?targetName WHERE {
  {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_targetRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-CAB5DD5D-BE94-4F7E-A643-81D13F16131A> .
    ?edge bbo:has_sourceRef ?source .
    OPTIONAL { ?source bbo:name ?sourceName . }
    BIND("incoming" AS ?edgeType)
  }
  UNION
  {
    ?edge a bbo:SequenceFlow .
    ?edge bbo:has_sourceRef <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-CAB5DD5D-BE94-4F7E-A643-81D13F16131A> .
    ?edge bbo:has_targetRef ?target .
    OPTIONAL { ?target bbo:name ?targetName . }
    BIND("outgoing" AS ?edgeType)
  }
}
LIMIT 30

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elemType ?elemName ?elem WHERE {
  {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-811BD5FE-A066-45C4-8222-7F95EA574C02> bbo:has_sourceRef ?elem .
  }
  UNION
  {
    <https://www.teamingai-project.eu/kg/process/qualityInspection/sid-EA75AFAE-AD1B-45EF-8FCB-883A26E19ED3> bbo:has_targetRef ?elem .
  }
  ?elem a ?elemType .
  OPTIONAL { ?elem bbo:name ?elemName . }
}
LIMIT 20
